import{_ as a,c as o,o as t,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Agentes de IA: Apresentação de 10 Especialistas | oh-my-opencode","description":"Aprenda sobre os 10 agentes de IA do oh-my-opencode. Selecione agentes com base no tipo de tarefa para alcançar colaboração eficiente e execução paralela.","frontmatter":{"title":"Agentes de IA: Apresentação de 10 Especialistas | oh-my-opencode","sidebarTitle":"Conheça 10 Especialistas de IA","subtitle":"Agentes de IA: Apresentação de 10 Especialistas","description":"Aprenda sobre os 10 agentes de IA do oh-my-opencode. Selecione agentes com base no tipo de tarefa para alcançar colaboração eficiente e execução paralela.","tags":["agentes-ia","orquestração"],"prerequisite":["start-sisyphus-orchestrator"],"order":60},"headers":[],"relativePath":"pt/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md","filePath":"pt/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"}'),r={name:"pt/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"};function i(n,e,d,l,p,c){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="equipe-de-agentes-de-ia-apresentacao-de-10-especialistas" tabindex="-1">Equipe de Agentes de IA: Apresentação de 10 Especialistas <a class="header-anchor" href="#equipe-de-agentes-de-ia-apresentacao-de-10-especialistas" aria-label="Permalink to &quot;Equipe de Agentes de IA: Apresentação de 10 Especialistas&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><ul><li>Compreender as responsabilidades e especialidades dos 10 agentes de IA integrados</li><li>Selecionar rapidamente o agente mais adequado com base no tipo de tarefa</li><li>Entender os mecanismos de colaboração entre agentes (delegação, paralelização, revisão)</li><li>Dominar as restrições de permissões e cenários de uso de diferentes agentes</li></ul><h2 id="ideia-central-colaborar-como-uma-equipe-real" tabindex="-1">Ideia Central: Colaborar Como uma Equipe Real <a class="header-anchor" href="#ideia-central-colaborar-como-uma-equipe-real" aria-label="Permalink to &quot;Ideia Central: Colaborar Como uma Equipe Real&quot;">​</a></h2><p>A ideia central do <strong>oh-my-opencode</strong> é: <strong>não trate a IA como um assistente onipotente, mas como uma equipe profissional</strong>.</p><p>Em uma equipe de desenvolvimento real, você precisa de:</p><ul><li><strong>Orquestrador Principal</strong> (Tech Lead): responsável por planejamento, alocação de tarefas e acompanhamento de progresso</li><li><strong>Consultor de Arquitetura</strong> (Architect): fornece decisões técnicas e recomendações de design de arquitetura</li><li><strong>Revisor de Código</strong> (Reviewer): verifica a qualidade do código e identifica problemas potenciais</li><li><strong>Especialista em Pesquisa</strong> (Researcher): busca documentação, pesquisa implementações open source e investiga melhores práticas</li><li><strong>Detetive de Código</strong> (Searcher): localiza rapidamente código, encontra referências e compreende implementações existentes</li><li><strong>Designer Frontend</strong> (Frontend Designer): projeta UI e ajusta estilos</li><li><strong>Especialista Git</strong> (Git Master): faz commits de código, gerencia branches e pesquisa histórico</li></ul><p>O oh-my-opencode transformou esses papéis em 10 agentes de IA profissionais que você pode combinar e usar de forma flexível com base no tipo de tarefa.</p><h2 id="detalhamento-dos-10-agentes" tabindex="-1">Detalhamento dos 10 Agentes <a class="header-anchor" href="#detalhamento-dos-10-agentes" aria-label="Permalink to &quot;Detalhamento dos 10 Agentes&quot;">​</a></h2><h3 id="orquestradores-principais-2" tabindex="-1">Orquestradores Principais (2) <a class="header-anchor" href="#orquestradores-principais-2" aria-label="Permalink to &quot;Orquestradores Principais (2)&quot;">​</a></h3><h4 id="sisyphus-orquestrador-principal" tabindex="-1">Sisyphus - Orquestrador Principal <a class="header-anchor" href="#sisyphus-orquestrador-principal" aria-label="Permalink to &quot;Sisyphus - Orquestrador Principal&quot;">​</a></h4><p><strong>Papel</strong>: Orquestrador principal, seu líder técnico primário</p><p><strong>Capacidades</strong>:</p><ul><li>Raciocínio profundo (32k thinking budget)</li><li>Planejamento e delegação de tarefas complexas</li><li>Execução de modificações e refatorações de código</li><li>Gerenciamento de todo o fluxo de desenvolvimento</li></ul><p><strong>Modelo Recomendado</strong>: <code>anthropic/claude-opus-4-5</code> (temperature: 0.1)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Tarefas de desenvolvimento diárias (novas funcionalidades, correção de bugs)</li><li>Problemas complexos que exigem raciocínio profundo</li><li>Decomposição e execução de tarefas em múltiplas etapas</li><li>Cenários que exigem delegação paralela a outros agentes</li></ul><p><strong>Método de Invocação</strong>:</p><ul><li>Agente principal padrão (&quot;Sisyphus&quot; no seletor de Agentes OpenCode)</li><li>Digite a tarefa diretamente no prompt, sem necessidade de palavras-chave especiais</li></ul><p><strong>Permissões</strong>: Permissões completas de ferramentas (write, edit, bash, delegate_task, etc.)</p><hr><h4 id="atlas-gerenciador-de-todo" tabindex="-1">Atlas - Gerenciador de TODO <a class="header-anchor" href="#atlas-gerenciador-de-todo" aria-label="Permalink to &quot;Atlas - Gerenciador de TODO&quot;">​</a></h4><p><strong>Papel</strong>: Orquestrador principal, focado em gerenciamento de listas TODO e rastreamento de execução de tarefas</p><p><strong>Capacidades</strong>:</p><ul><li>Gerenciar e rastrear listas TODO</li><li>Execução sistemática de planos</li><li>Monitoramento de progresso de tarefas</li></ul><p><strong>Modelo Recomendado</strong>: <code>anthropic/claude-opus-4-5</code> (temperature: 0.1)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Iniciar execução de projeto com o comando <code>/start-work</code></li><li>Necessidade de completar tarefas rigorosamente de acordo com o plano</li><li>Rastreamento sistemático de progresso de tarefas</li></ul><p><strong>Método de Invocação</strong>:</p><ul><li>Usar comando slash <code>/start-work</code></li><li>Ativação automática via Atlas Hook</li></ul><p><strong>Permissões</strong>: Permissões completas de ferramentas</p><hr><h3 id="consultores-e-revisores-3" tabindex="-1">Consultores e Revisores (3) <a class="header-anchor" href="#consultores-e-revisores-3" aria-label="Permalink to &quot;Consultores e Revisores (3)&quot;">​</a></h3><h4 id="oracle-consultor-estrategico" tabindex="-1">Oracle - Consultor Estratégico <a class="header-anchor" href="#oracle-consultor-estrategico" aria-label="Permalink to &quot;Oracle - Consultor Estratégico&quot;">​</a></h4><p><strong>Papel</strong>: Consultor técnico somente leitura, especialista em raciocínio de alto nível</p><p><strong>Capacidades</strong>:</p><ul><li>Recomendações de decisões arquiteturais</li><li>Diagnóstico de problemas complexos</li><li>Revisão de código (somente leitura)</li><li>Análise de trade-offs entre múltiplos sistemas</li></ul><p><strong>Modelo Recomendado</strong>: <code>openai/gpt-5.2</code> (temperature: 0.1)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Design de arquitetura complexa</li><li>Auto-revisão após completar trabalho importante</li><li>Depuração difícil após 2+ tentativas de correção falhadas</li><li>Padrões de código ou arquitetura desconhecidos</li><li>Questões relacionadas a segurança/desempenho</li></ul><p><strong>Condições de Ativação</strong>:</p><ul><li>Prompt contém <code>@oracle</code> ou usa <code>delegate_task(agent=&quot;oracle&quot;)</code></li><li>Recomendação automática em decisões arquiteturais complexas</li></ul><p><strong>Restrições</strong>: Permissões somente leitura (proibido write, edit, task, delegate_task)</p><p><strong>Princípios Fundamentais</strong>:</p><ul><li><strong>Minimalismo</strong>: tendência para a solução mais simples</li><li><strong>Aproveitar Recursos Existentes</strong>: priorizar modificação do código atual, evitar introdução de novas dependências</li><li><strong>Experiência do Desenvolvedor em Primeiro Lugar</strong>: legibilidade, manutenibilidade &gt; desempenho teórico</li><li><strong>Caminho Único e Claro</strong>: fornecer uma recomendação principal, oferecer alternativas apenas quando as diferenças de trade-off são significativas</li></ul><hr><h4 id="metis-analista-de-pre-planejamento" tabindex="-1">Metis - Analista de Pré-Planejamento <a class="header-anchor" href="#metis-analista-de-pre-planejamento" aria-label="Permalink to &quot;Metis - Analista de Pré-Planejamento&quot;">​</a></h4><p><strong>Papel</strong>: Especialista em análise de requisitos e avaliação de riscos antes do planejamento</p><p><strong>Capacidades</strong>:</p><ul><li>Identificar requisitos ocultos e não especificados</li><li>Detectar ambiguidades que podem levar a falhas de IA</li><li>Sinalizar padrões potenciais de AI-slop (sobre-engenharia, expansão de escopo)</li><li>Preparar instruções para agentes de planejamento</li></ul><p><strong>Modelo Recomendado</strong>: <code>anthropic/claude-sonnet-4-5</code> (temperature: 0.3)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Antes do planejamento do Prometheus</li><li>Quando a solicitação do usuário é vaga ou aberta</li><li>Prevenir padrões de sobre-engenharia de IA</li></ul><p><strong>Método de Invocação</strong>: Invocação automática pelo Prometheus (modo entrevista)</p><p><strong>Restrições</strong>: Permissões somente leitura (proibido write, edit, task, delegate_task)</p><p><strong>Fluxo Principal</strong>:</p><ol><li><strong>Classificação de Intenção</strong>: refatoração / construir do zero / tarefa média / colaboração / arquitetura / pesquisa</li><li><strong>Análise Específica de Intenção</strong>: fornecer recomendações direcionadas com base em diferentes tipos</li><li><strong>Geração de Perguntas</strong>: gerar perguntas claras para o usuário</li><li><strong>Preparação de Instruções</strong>: gerar instruções claras de &quot;MUST&quot; e &quot;MUST NOT&quot; para o Prometheus</li></ol><hr><h4 id="momus-revisor-de-planos" tabindex="-1">Momus - Revisor de Planos <a class="header-anchor" href="#momus-revisor-de-planos" aria-label="Permalink to &quot;Momus - Revisor de Planos&quot;">​</a></h4><p><strong>Papel</strong>: Especialista rigoroso em revisão de planos, identifica todas as omissões e pontos ambíguos</p><p><strong>Capacidades</strong>:</p><ul><li>Verificar clareza, verificabilidade e completude do plano</li><li>Verificar todas as referências de arquivos e contexto</li><li>Simular etapas de implementação real</li><li>Identificar omissões críticas</li></ul><p><strong>Modelo Recomendado</strong>: <code>anthropic/claude-sonnet-4-5</code> (temperature: 0.1)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Após o Prometheus criar um plano de trabalho</li><li>Antes de executar listas TODO complexas</li><li>Validar qualidade do plano</li></ul><p><strong>Método de Invocação</strong>: Invocação automática pelo Prometheus</p><p><strong>Restrições</strong>: Permissões somente leitura (proibido write, edit, task, delegate_task)</p><p><strong>Quatro Critérios de Revisão</strong>:</p><ol><li><strong>Clareza do Trabalho</strong>: cada tarefa especifica fontes de referência?</li><li><strong>Critérios de Verificação e Aceitação</strong>: existem métodos específicos de verificação de sucesso?</li><li><strong>Completude do Contexto</strong>: contexto suficiente fornecido (limiar de confiança de 90%)?</li><li><strong>Compreensão Geral</strong>: o desenvolvedor entende o WHY, WHAT e HOW?</li></ol><p><strong>Princípio Fundamental</strong>: <strong>Revisor de documentos, não consultor de design</strong>. Avalia se &quot;o plano está claro o suficiente para ser executado&quot;, não se &quot;o método escolhido está correto&quot;.</p><hr><h3 id="pesquisa-e-exploracao-3" tabindex="-1">Pesquisa e Exploração (3) <a class="header-anchor" href="#pesquisa-e-exploracao-3" aria-label="Permalink to &quot;Pesquisa e Exploração (3)&quot;">​</a></h3><h4 id="librarian-especialista-em-pesquisa-multi-repositorio" tabindex="-1">Librarian - Especialista em Pesquisa Multi-Repositório <a class="header-anchor" href="#librarian-especialista-em-pesquisa-multi-repositorio" aria-label="Permalink to &quot;Librarian - Especialista em Pesquisa Multi-Repositório&quot;">​</a></h4><p><strong>Papel</strong>: Especialista em compreensão de repositórios de código open source, especializado em encontrar documentação e exemplos de implementação</p><p><strong>Capacidades</strong>:</p><ul><li>GitHub CLI: clonar repositórios, pesquisar issues/PRs, visualizar histórico</li><li>Context7: consultar documentação oficial</li><li>Web Search: pesquisar informações mais recentes</li><li>Gerar evidências com permalinks</li></ul><p><strong>Modelo Recomendado</strong>: <code>opencode/big-pickle</code> (temperature: 0.1)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>&quot;Como usar [biblioteca]?&quot;</li><li>&quot;Quais são as melhores práticas para [recurso do framework]?&quot;</li><li>&quot;Por que [dependência externa] se comporta assim?&quot;</li><li>&quot;Encontrar exemplos de uso de [biblioteca]&quot;</li></ul><p><strong>Condições de Ativação</strong>:</p><ul><li>Ativação automática ao mencionar bibliotecas/fontes externas</li><li>Prompt contém <code>@librarian</code></li></ul><p><strong>Classificação de Tipos de Solicitação</strong>:</p><ul><li><strong>Tipo A (Conceitual)</strong>: &quot;Como fazer X?&quot;, &quot;Melhores práticas&quot;</li><li><strong>Tipo B (Referência de Implementação)</strong>: &quot;Como X implementa Y?&quot;, &quot;Mostrar código-fonte de Z&quot;</li><li><strong>Tipo C (Contexto e Histórico)</strong>: &quot;Por que mudou assim?&quot;, &quot;Histórico de X?&quot;</li><li><strong>Tipo D (Pesquisa Abrangente)</strong>: solicitações complexas/vagas</li></ul><p><strong>Restrições</strong>: Permissões somente leitura (proibido write, edit, task, delegate_task, call_omo_agent)</p><p><strong>Requisito Obrigatório</strong>: Todas as declarações de código devem incluir permalinks do GitHub</p><hr><h4 id="explore-especialista-em-exploracao-rapida-de-codebase" tabindex="-1">Explore - Especialista em Exploração Rápida de Codebase <a class="header-anchor" href="#explore-especialista-em-exploracao-rapida-de-codebase" aria-label="Permalink to &quot;Explore - Especialista em Exploração Rápida de Codebase&quot;">​</a></h4><p><strong>Papel</strong>: Especialista em busca de código com consciência de contexto</p><p><strong>Capacidades</strong>:</p><ul><li>Ferramentas LSP: definições, referências, navegação de símbolos</li><li>AST-Grep: busca de padrões estruturais</li><li>Grep: busca de padrões de texto</li><li>Glob: correspondência de padrões de nomes de arquivos</li><li>Execução paralela (3+ ferramentas executando simultaneamente)</li></ul><p><strong>Modelo Recomendado</strong>: <code>opencode/gpt-5-nano</code> (temperature: 0.1)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Busca ampla que requer 2+ ângulos de pesquisa</li><li>Estrutura de módulo desconhecida</li><li>Descoberta de padrões entre camadas</li><li>Encontrar &quot;Onde está X?&quot;, &quot;Qual arquivo tem Y?&quot;</li></ul><p><strong>Condições de Ativação</strong>:</p><ul><li>Ativação automática quando 2+ módulos estão envolvidos</li><li>Prompt contém <code>@explore</code></li></ul><p><strong>Formato de Saída Obrigatório</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;analysis&gt;</span></span>
<span class="line"><span>**Literal Request**: [solicitação literal do usuário]</span></span>
<span class="line"><span>**Actual Need**: [o que realmente é necessário]</span></span>
<span class="line"><span>**Success Looks Like**: [como deve ser o sucesso]</span></span>
<span class="line"><span>&lt;/analysis&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;results&gt;</span></span>
<span class="line"><span>&lt;files&gt;</span></span>
<span class="line"><span>- /absolute/path/to/file1.ts — [por que este arquivo é relevante]</span></span>
<span class="line"><span>- /absolute/path/to/file2.ts — [por que este arquivo é relevante]</span></span>
<span class="line"><span>&lt;/files&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;answer&gt;</span></span>
<span class="line"><span>[resposta direta à necessidade real]</span></span>
<span class="line"><span>&lt;/answer&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;next_steps&gt;</span></span>
<span class="line"><span>[o que fazer a seguir]</span></span>
<span class="line"><span>&lt;/next_steps&gt;</span></span>
<span class="line"><span>&lt;/results&gt;</span></span></code></pre></div><p><strong>Restrições</strong>: Permissões somente leitura (proibido write, edit, task, delegate_task, call_omo_agent)</p><hr><h4 id="multimodal-looker-especialista-em-analise-de-midia" tabindex="-1">Multimodal Looker - Especialista em Análise de Mídia <a class="header-anchor" href="#multimodal-looker-especialista-em-analise-de-midia" aria-label="Permalink to &quot;Multimodal Looker - Especialista em Análise de Mídia&quot;">​</a></h4><p><strong>Papel</strong>: Interpretar arquivos de mídia que não podem ser lidos como texto puro</p><p><strong>Capacidades</strong>:</p><ul><li>PDF: extrair texto, estrutura, tabelas, dados de seções específicas</li><li>Imagens: descrever layout, elementos de UI, texto, gráficos</li><li>Diagramas: explicar relacionamentos, fluxos, arquitetura</li></ul><p><strong>Modelo Recomendado</strong>: <code>google/gemini-3-flash</code> (temperature: 0.1)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Necessidade de extrair dados estruturados de PDFs</li><li>Descrever elementos de UI ou gráficos em imagens</li><li>Analisar diagramas em documentação técnica</li></ul><p><strong>Método de Invocação</strong>: Ativação automática via ferramenta <code>look_at</code></p><p><strong>Restrições</strong>: <strong>Whitelist somente leitura</strong> (apenas ferramenta read permitida)</p><hr><h3 id="planejamento-e-execucao-2" tabindex="-1">Planejamento e Execução (2) <a class="header-anchor" href="#planejamento-e-execucao-2" aria-label="Permalink to &quot;Planejamento e Execução (2)&quot;">​</a></h3><h4 id="prometheus-planejador-estrategico" tabindex="-1">Prometheus - Planejador Estratégico <a class="header-anchor" href="#prometheus-planejador-estrategico" aria-label="Permalink to &quot;Prometheus - Planejador Estratégico&quot;">​</a></h4><p><strong>Papel</strong>: Especialista em coleta de requisitos estilo entrevista e geração de planos de trabalho</p><p><strong>Capacidades</strong>:</p><ul><li>Modo entrevista: fazer perguntas contínuas até que os requisitos estejam claros</li><li>Geração de plano de trabalho: documento de plano estruturado em Markdown</li><li>Delegação paralela: consultar Oracle, Metis, Momus para validar plano</li></ul><p><strong>Modelo Recomendado</strong>: <code>anthropic/claude-opus-4-5</code> (temperature: 0.1)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Criar planos detalhados para projetos complexos</li><li>Projetos que exigem requisitos claros</li><li>Fluxo de trabalho sistemático</li></ul><p><strong>Método de Invocação</strong>:</p><ul><li>Prompt contém <code>@prometheus</code> ou &quot;usar Prometheus&quot;</li><li>Usar comando slash <code>/start-work</code></li></ul><p><strong>Fluxo de Trabalho</strong>:</p><ol><li><strong>Modo Entrevista</strong>: fazer perguntas contínuas até que os requisitos estejam claros</li><li><strong>Rascunhar Plano</strong>: gerar plano estruturado em Markdown</li><li><strong>Delegação Paralela</strong>: <ul><li><code>delegate_task(agent=&quot;oracle&quot;, prompt=&quot;revisar decisões arquiteturais&quot;)</code> → execução em segundo plano</li><li><code>delegate_task(agent=&quot;metis&quot;, prompt=&quot;identificar riscos potenciais&quot;)</code> → execução em segundo plano</li><li><code>delegate_task(agent=&quot;momus&quot;, prompt=&quot;validar completude do plano&quot;)</code> → execução em segundo plano</li></ul></li><li><strong>Integrar Feedback</strong>: refinar plano</li><li><strong>Saída do Plano</strong>: salvar em <code>.sisyphus/plans/{name}.md</code></li></ol><p><strong>Restrições</strong>: Apenas planejamento, não implementação de código (forçado pelo Hook <code>prometheus-md-only</code>)</p><hr><h4 id="sisyphus-junior-executor-de-tarefas" tabindex="-1">Sisyphus Junior - Executor de Tarefas <a class="header-anchor" href="#sisyphus-junior-executor-de-tarefas" aria-label="Permalink to &quot;Sisyphus Junior - Executor de Tarefas&quot;">​</a></h4><p><strong>Papel</strong>: Executor de sub-agentes gerado por categoria</p><p><strong>Capacidades</strong>:</p><ul><li>Herdar configuração de Categoria (modelo, temperature, prompt_append)</li><li>Carregar Skills (habilidades especializadas)</li><li>Executar subtarefas delegadas</li></ul><p><strong>Modelo Recomendado</strong>: Herdado da Categoria (padrão <code>anthropic/claude-sonnet-4-5</code>)</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Geração automática ao usar <code>delegate_task(category=&quot;...&quot;, skills=[&quot;...&quot;])</code></li><li>Tarefas que exigem combinação específica de Categoria e Skill</li><li>Tarefas rápidas e leves (Categoria &quot;quick&quot; usa modelo Haiku)</li></ul><p><strong>Método de Invocação</strong>: Geração automática via ferramenta <code>delegate_task</code></p><p><strong>Restrições</strong>: Proibido task, delegate_task (não pode delegar novamente)</p><hr><h2 id="referencia-rapida-de-invocacao-de-agentes" tabindex="-1">Referência Rápida de Invocação de Agentes <a class="header-anchor" href="#referencia-rapida-de-invocacao-de-agentes" aria-label="Permalink to &quot;Referência Rápida de Invocação de Agentes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agente</th><th>Método de Invocação</th><th>Condição de Ativação</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>Agente principal padrão</td><td>Tarefas de desenvolvimento diárias</td></tr><tr><td><strong>Atlas</strong></td><td>Comando <code>/start-work</code></td><td>Iniciar execução de projeto</td></tr><tr><td><strong>Oracle</strong></td><td><code>@oracle</code> ou <code>delegate_task(agent=&quot;oracle&quot;)</code></td><td>Decisões arquiteturais complexas, 2+ tentativas de correção falhadas</td></tr><tr><td><strong>Librarian</strong></td><td><code>@librarian</code> ou <code>delegate_task(agent=&quot;librarian&quot;)</code></td><td>Ativação automática ao mencionar bibliotecas/fontes externas</td></tr><tr><td><strong>Explore</strong></td><td><code>@explore</code> ou <code>delegate_task(agent=&quot;explore&quot;)</code></td><td>Ativação automática quando 2+ módulos estão envolvidos</td></tr><tr><td><strong>Multimodal Looker</strong></td><td>Ferramenta <code>look_at</code></td><td>Necessidade de analisar PDF/imagens</td></tr><tr><td><strong>Prometheus</strong></td><td><code>@prometheus</code> ou <code>/start-work</code></td><td>Prompt contém &quot;Prometheus&quot; ou necessidade de planejamento</td></tr><tr><td><strong>Metis</strong></td><td>Invocação automática pelo Prometheus</td><td>Análise automática antes do planejamento</td></tr><tr><td><strong>Momus</strong></td><td>Invocação automática pelo Prometheus</td><td>Revisão automática após geração do plano</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td><code>delegate_task(category=...)</code></td><td>Geração automática ao usar Categoria/Skill</td></tr></tbody></table><hr><h2 id="quando-usar-qual-agente" tabindex="-1">Quando Usar Qual Agente <a class="header-anchor" href="#quando-usar-qual-agente" aria-label="Permalink to &quot;Quando Usar Qual Agente&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Árvore de Decisão Rápida</p><p><strong>Cenário 1: Desenvolvimento diário (escrever código, corrigir bugs)</strong> → <strong>Sisyphus</strong> (padrão)</p><p><strong>Cenário 2: Decisões arquiteturais complexas</strong> → Consultar <strong>@oracle</strong></p><p><strong>Cenário 3: Necessidade de encontrar documentação ou implementação de biblioteca externa</strong> → <strong>@librarian</strong> ou ativação automática</p><p><strong>Cenário 4: Codebase desconhecido, necessidade de encontrar código relacionado</strong> → <strong>@explore</strong> ou ativação automática (2+ módulos)</p><p><strong>Cenário 5: Projeto complexo que requer plano detalhado</strong> → <strong>@prometheus</strong> ou usar <code>/start-work</code></p><p><strong>Cenário 6: Necessidade de analisar PDF ou imagem</strong> → Ferramenta <strong>look_at</strong> (ativa automaticamente Multimodal Looker)</p><p><strong>Cenário 7: Tarefa rápida e simples, quer economizar</strong> → <code>delegate_task(category=&quot;quick&quot;)</code></p><p><strong>Cenário 8: Necessidade de operações profissionais Git</strong> → <code>delegate_task(category=&quot;quick&quot;, skills=[&quot;git-master&quot;])</code></p><p><strong>Cenário 9: Necessidade de design de UI frontend</strong> → <code>delegate_task(category=&quot;visual-engineering&quot;)</code></p><p><strong>Cenário 10: Necessidade de tarefa de raciocínio de alto nível</strong> → <code>delegate_task(category=&quot;ultrabrain&quot;)</code></p></div><hr><h2 id="exemplos-de-colaboracao-de-agentes-fluxo-de-trabalho-completo" tabindex="-1">Exemplos de Colaboração de Agentes: Fluxo de Trabalho Completo <a class="header-anchor" href="#exemplos-de-colaboracao-de-agentes-fluxo-de-trabalho-completo" aria-label="Permalink to &quot;Exemplos de Colaboração de Agentes: Fluxo de Trabalho Completo&quot;">​</a></h2><h3 id="exemplo-1-desenvolvimento-de-funcionalidade-complexa" tabindex="-1">Exemplo 1: Desenvolvimento de Funcionalidade Complexa <a class="header-anchor" href="#exemplo-1-desenvolvimento-de-funcionalidade-complexa" aria-label="Permalink to &quot;Exemplo 1: Desenvolvimento de Funcionalidade Complexa&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Usuário: Desenvolver um sistema de autenticação de usuários</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Sisyphus recebe a tarefa</span></span>
<span class="line"><span>  → Analisa requisitos, descobre necessidade de biblioteca externa (JWT)</span></span>
<span class="line"><span>  → Delegação paralela:</span></span>
<span class="line"><span>    - @librarian: &quot;Encontrar melhores práticas de JWT no Next.js&quot; → [segundo plano]</span></span>
<span class="line"><span>    - @explore: &quot;Encontrar código relacionado a autenticação existente&quot; → [segundo plano]</span></span>
<span class="line"><span>  → Aguarda resultados, integra informações</span></span>
<span class="line"><span>  → Implementa funcionalidade de autenticação JWT</span></span>
<span class="line"><span>  → Após conclusão, delega:</span></span>
<span class="line"><span>    - @oracle: &quot;Revisar design de arquitetura&quot; → [segundo plano]</span></span>
<span class="line"><span>  → Otimiza com base em recomendações</span></span></code></pre></div><hr><h3 id="exemplo-2-planejamento-de-projeto" tabindex="-1">Exemplo 2: Planejamento de Projeto <a class="header-anchor" href="#exemplo-2-planejamento-de-projeto" aria-label="Permalink to &quot;Exemplo 2: Planejamento de Projeto&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Usuário: Usar Prometheus para planejar este projeto</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Prometheus recebe a tarefa</span></span>
<span class="line"><span>  → Modo entrevista:</span></span>
<span class="line"><span>    - Pergunta 1: Quais são as funcionalidades principais?</span></span>
<span class="line"><span>    - [Resposta do usuário]</span></span>
<span class="line"><span>    - Pergunta 2: Qual é o público-alvo?</span></span>
<span class="line"><span>    - [Resposta do usuário]</span></span>
<span class="line"><span>    - ...</span></span>
<span class="line"><span>  → Após requisitos claros, delegação paralela:</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;oracle&quot;, prompt=&quot;revisar decisões arquiteturais&quot;) → [segundo plano]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;metis&quot;, prompt=&quot;identificar riscos potenciais&quot;) → [segundo plano]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;momus&quot;, prompt=&quot;validar completude do plano&quot;) → [segundo plano]</span></span>
<span class="line"><span>  → Aguarda conclusão de todas as tarefas em segundo plano</span></span>
<span class="line"><span>  → Integra feedback, refina plano</span></span>
<span class="line"><span>  → Gera documento de plano em Markdown</span></span>
<span class="line"><span>→ Usuário revisa plano, confirma</span></span>
<span class="line"><span>→ Usa /start-work para iniciar execução</span></span></code></pre></div><hr><h2 id="permissoes-e-restricoes-de-agentes" tabindex="-1">Permissões e Restrições de Agentes <a class="header-anchor" href="#permissoes-e-restricoes-de-agentes" aria-label="Permalink to &quot;Permissões e Restrições de Agentes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agente</th><th>write</th><th>edit</th><th>bash</th><th>delegate_task</th><th>webfetch</th><th>read</th><th>LSP</th><th>AST-Grep</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Atlas</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Oracle</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Librarian</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Explore</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Multimodal Looker</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Prometheus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Metis</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Momus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td>✅</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><hr><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>Os 10 agentes de IA do oh-my-opencode cobrem todos os aspectos do fluxo de desenvolvimento:</p><ul><li><strong>Orquestração e Execução</strong>: Sisyphus (orquestrador principal), Atlas (gerenciamento TODO)</li><li><strong>Consultores e Revisores</strong>: Oracle (consultor estratégico), Metis (análise pré-planejamento), Momus (revisão de planos)</li><li><strong>Pesquisa e Exploração</strong>: Librarian (pesquisa multi-repositório), Explore (exploração de codebase), Multimodal Looker (análise de mídia)</li><li><strong>Planejamento</strong>: Prometheus (planejamento estratégico), Sisyphus Junior (execução de subtarefas)</li></ul><p><strong>Pontos-Chave</strong>:</p><ol><li>Não trate a IA como assistente onipotente, trate como equipe profissional</li><li>Selecione o agente mais adequado com base no tipo de tarefa</li><li>Aproveite a delegação paralela para aumentar a eficiência (Librarian, Explore, Oracle podem executar em segundo plano)</li><li>Entenda as restrições de permissões de cada agente (agentes somente leitura não podem modificar código)</li><li>A colaboração entre agentes pode formar um fluxo de trabalho completo (planejamento → execução → revisão)</li></ol><hr><h2 id="previa-da-proxima-aula" tabindex="-1">Prévia da Próxima Aula <a class="header-anchor" href="#previa-da-proxima-aula" aria-label="Permalink to &quot;Prévia da Próxima Aula&quot;">​</a></h2><blockquote><p>Na próxima aula aprenderemos <strong><a href="./../prometheus-planning/">Planejamento com Prometheus: Coleta de Requisitos Estilo Entrevista</a></strong>.</p><p>Você vai aprender:</p><ul><li>Como usar o Prometheus para coleta de requisitos estilo entrevista</li><li>Como gerar planos de trabalho estruturados</li><li>Como fazer Metis e Momus validarem planos</li><li>Como obter e cancelar tarefas em segundo plano</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de Código Fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código fonte</strong></summary><blockquote><p>Última atualização: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Agente</th><th>Caminho do Arquivo</th><th>Linha</th></tr></thead><tbody><tr><td>Orquestrador Principal Sisyphus</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus.ts</code></a></td><td>-</td></tr><tr><td>Orquestrador Principal Atlas</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/atlas.ts" target="_blank" rel="noreferrer"><code>src/agents/atlas.ts</code></a></td><td>-</td></tr><tr><td>Consultor Oracle</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/oracle.ts" target="_blank" rel="noreferrer"><code>src/agents/oracle.ts</code></a></td><td>1-123</td></tr><tr><td>Especialista em Pesquisa Librarian</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/librarian.ts" target="_blank" rel="noreferrer"><code>src/agents/librarian.ts</code></a></td><td>1-327</td></tr><tr><td>Especialista em Busca Explore</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/explore.ts" target="_blank" rel="noreferrer"><code>src/agents/explore.ts</code></a></td><td>1-123</td></tr><tr><td>Multimodal Looker</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/multimodal-looker.ts" target="_blank" rel="noreferrer"><code>src/agents/multimodal-looker.ts</code></a></td><td>1-57</td></tr><tr><td>Planejador Prometheus</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/prometheus-prompt.ts" target="_blank" rel="noreferrer"><code>src/agents/prometheus-prompt.ts</code></a></td><td>1-1196</td></tr><tr><td>Análise Pré-Planejamento Metis</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/metis.ts" target="_blank" rel="noreferrer"><code>src/agents/metis.ts</code></a></td><td>1-316</td></tr><tr><td>Revisor de Planos Momus</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/momus.ts" target="_blank" rel="noreferrer"><code>src/agents/momus.ts</code></a></td><td>1-445</td></tr><tr><td>Sisyphus Junior</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus-junior.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus-junior.ts</code></a></td><td>-</td></tr><tr><td>Definição de Metadados de Agentes</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/types.ts" target="_blank" rel="noreferrer"><code>src/agents/types.ts</code></a></td><td>-</td></tr><tr><td>Restrições de Ferramentas de Agentes</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/shared/permission-compat.ts" target="_blank" rel="noreferrer"><code>src/shared/permission-compat.ts</code></a></td><td>-</td></tr></tbody></table><p><strong>Configurações Principais</strong>:</p><ul><li><code>ORACLE_PROMPT_METADATA</code>: Metadados do agente Oracle (condições de ativação, cenários de uso)</li><li><code>LIBRARIAN_PROMPT_METADATA</code>: Metadados do agente Librarian</li><li><code>EXPLORE_PROMPT_METADATA</code>: Metadados do agente Explore</li><li><code>MULTIMODAL_LOOKER_PROMPT_METADATA</code>: Metadados do agente Multimodal Looker</li><li><code>METIS_SYSTEM_PROMPT</code>: Prompt do sistema do agente Metis</li><li><code>MOMUS_SYSTEM_PROMPT</code>: Prompt do sistema do agente Momus</li></ul><p><strong>Funções Principais</strong>:</p><ul><li><code>createOracleAgent(model)</code>: Criar configuração do agente Oracle</li><li><code>createLibrarianAgent(model)</code>: Criar configuração do agente Librarian</li><li><code>createExploreAgent(model)</code>: Criar configuração do agente Explore</li><li><code>createMultimodalLookerAgent(model)</code>: Criar configuração do agente Multimodal Looker</li><li><code>createMetisAgent(model)</code>: Criar configuração do agente Metis</li><li><code>createMomusAgent(model)</code>: Criar configuração do agente Momus</li></ul><p><strong>Restrições de Permissões</strong>:</p><ul><li><code>createAgentToolRestrictions()</code>: Criar restrições de ferramentas de agentes (usado por Oracle, Librarian, Explore, Metis, Momus)</li><li><code>createAgentToolAllowlist()</code>: Criar whitelist de ferramentas de agentes (usado por Multimodal Looker)</li></ul></details>`,160)])])}const m=a(r,[["render",i]]);export{g as __pageData,m as default};
